let data = msg.payload;
let obj = {};

for (let val of data) {
    obj[val.mac] = val[val.mac]
}
msg.payload = obj;
return msg;

if (msg.topic == "update") {
    context.set("endpoints", msg.payload);
    node.status({ fill: "green", shape: "ring", text: "updated..." });
    return null;
}

if (msg.topic == "get") {
    let data = context.get("endpoints");
    node.status({ fill: "blue", shape: "ring", text: data.length });
    msg.config_url = data;
    return msg;
}

const xalarms = global.get("xalarms") || {};
const xstream = global.get("xstream") || {};
let data = msg.payload || {};

const entries = (obj) => Object.entries(obj);
const decode = (t) => decodeURIComponent(t ?? "");

let date_now = new Date().getTime();

const counter_alarm = (devices = {}) => {
    let active = 0;
    let total = Object.keys(devices).length;

    for (const [, dev] of entries(devices)) {
        for (const [, al] of entries(dev.alarms || {})) {
            if (al.en && al.value) active++;
        }
    }
    return { active, total };
}

// BUILD SENSOR DATA
function buildSensor(mac) {
    if (!data[mac]?.devices) return null;
    const devices = {};
    for (const d of data[mac].devices) {
        const realtime = [];
        const deviceStatus = [];
        const analogInput = [];
        const alarm = [];

        if (Array.isArray(d.chartDef)) {
            for (const c of d.chartDef) {
                realtime.push({
                    name: c.name,
                    value: c.value,
                    unit: c.unit
                });
            }
        }
        if (Array.isArray(d.deviceStatus)) {
            for (const s of d.deviceStatus) {
                deviceStatus.push({
                    point_id: s.pointId,
                    name: s.name,
                    value: s.value
                });
            }
        }
        if (Array.isArray(d.analogInput)) {
            for (const a of d.analogInput) {
                analogInput.push({
                    point_id: a.pointId,
                    name: a.name,
                    value: a.value,
                    unit: a.unit
                });
            }
        }
        if (Array.isArray(d.alarm)) {
            for (const al of d.alarm) {
                if (al.value) {
                    alarm.push({
                        point_id: al.pointId,
                        name: al.name,
                        value: al.value
                    });
                }
            }
        }
        devices[d.uid] = {
            name: decode(d.name),
            adr: d.adr,
            deviceid: d.uid,
            model: d.model,
            realTime: realtime,
            deviceStatus,
            analogInput,
            alarm,
        }
    }
    return {
        name: decode(data[mac].name),
        mac_address: data[mac].mac_address,
        on: data[mac].on,
        devices,
    }
}

// COMPARE + BUILD ACTIVE ALARMS
function comparesData(mac, owner) {
    let chk_watch = global.get("chk_watch") || {};
    let active_alarms = global.get("Active_Alarms") || {};

    const obj = {};
    const arr = {};
    arr[mac] = [];

    if (!xalarms[mac]?.devices) return obj;

    const sensor = buildSensor(mac);
    const status = counter_alarm(xalarms[mac].devices);

    for (const [did, dev] of entries(xalarms[mac].devices)) {
        if (!dev.alarms) continue;
        for (const [pid, al] of entries(dev.alarms || {})) {
            if (!al.en || !al.value) continue;
            const idx = `${mac}_${did}_${pid}`;

            if (!chk_watch[idx]) {
                chk_watch[idx] = {
                    note: "",
                    acknow: 0,
                    count: 0,
                    acknow_count: 0,
                    timestamp: date_now,
                }
            }
            const ts = chk_watch[idx].count > 0 ? chk_watch[idx].timestamp : active_alarms[idx]?.dateStart ?? date_now;
            arr[mac].push({
                xweb_name: decode(sensor?.name) ?? "",
                mac_address: sensor?.mac_address ?? mac,
                owner,
                device_name: decode(sensor?.devices[did]?.name) ?? "",
                device_adr: sensor?.devices[did]?.adr ?? "-",
                device_id: did,
                name: decode(al.name) ?? "",
                point_id: pid,
                status: al.value > 0 ? "Active" : "Normal",
                note: chk_watch[idx].note ?? "",
                acknow: chk_watch[idx]?.acknow,
                chk_watch: chk_watch[idx]?.count,
                timestamp: ts,
                startTime: active_alarms[idx]?.dateStart,
            })
        }
    }
    global.set("chk_watch", chk_watch);
    obj[mac] = {
        name: sensor?.name ?? "",
        mac_address: sensor?.mac_address,
        on: sensor?.on,
        devices: sensor?.devices ?? {},
        active_alarms: arr[mac],
        status: status
    };
    return obj;
}

const chk_offline = global.get("Offline") || {};

const arr_data = [];
for (const conf of msg.config_url) {
    const mac = conf.mac_address;
    const compares = comparesData(mac, conf.owner);

    if (!chk_offline[mac]) {
        arr_data.push({
            _attr: {
                site_name: data[mac]?.name ?? conf.xweb_name,
                status_acq: data[mac]?.on,
                mac,
                url: conf.url,
                communication: "Online",
                owner: conf.owner,
                branch_id: conf.branch_id,
                lastest_updated: xstream[mac]?.stream_data?.ts
            },
            _status: compares[mac]?.status ?? {},
            _active_alarms: compares[mac]?.active_alarms ?? [],
            _devices: compares[mac]?.devices ?? {},
        });
    } else {
        arr_data.push({
            _attr: {
                site_name: conf.xweb_name,
                status_acq: 0,
                mac,
                url: conf.url,
                communication: "Offline",
                owner: conf.owner,
                branch_id: conf.branch_id,
                lastest_updated: xstream[mac]?.stream_data?.ts ?? date_now,
            },
            _status: { active: 0, total: 0 },
            _active_alarms: [],
            _devices: {},
        })
    }
}

msg.payload = arr_data;
msg.filename = `/data/files/Data_All.txt`;
return msg;

const data = msg.payload || {};
const date_now = new Date().getTime();

// Counter Alarms
const counter_alarm = (devices = {}, mac) => {
    let active = 0;
    const total = Object.keys(devices).length;

    for (const d of Object.values(devices)) {
        for (const al of d.alarm || []) {
            if (al.value > 0) {
                active++;
                break;
            }
        }
    }
    return {
        [mac]: {
            active,
            total,
            alarm: active > 0 ? 1 : 0,
        }
    }
}
// Compares & Aggregate
function comparesData(mac) {
    let chk_watch = global.get("chk_watch") || {};
    let chk_commu = global.get("CheckCommunications") || {};

    if (!data[mac]) {
        return {
            [mac]: {
                mac_address: mac,
                on: 0,
                devices: [],
                active_alarm: [],
                status: { active: 0, total: 0 },
                chk_watch: 0,
                acknow: 0,
                acknow_count: 0,
                offline_count: 0,
                offline_timestamp: null
            }
        }
    }
    const devices = data[mac].devices || [];
    const status = counter_alarm(devices, mac)[mac];

    // Aggregate chk_watch
    let chk_sum = { count: 0, acknow: 0, acknow_count: 0 };
    for (const [key, v] of Object.entries(chk_watch)) {
        if (key.startsWith(mac)) {
            chk_sum.count += v.count || 0;
            chk_sum.acknow += v.acknow || 0;
            chk_sum.acknow_count += v.acknow_count || 0;
        }
    }

    // Aggregate Communication
    const commu = chk_commu[mac] || {};
    const offline_count = commu.offline_count || 0;
    const offline_timestamp = commu.offline_timestamp || null;

    // Build active alarm list.
    const active_alarm = [];
    for (const d of devices) {
        for (const al of d.alarm || []) {
            if (al.value > 0) {
                active_alarm.push({
                    xweb_name: data[mac].name,
                    mac_address: data[mac].mac_address,
                    device_name: d.name,
                    device_adr: d.adr,
                    device_id: d.uid,
                    name: al.name,
                    point_id: al.pointId,
                })
            }
        }
    }
    return {
        [mac]: {
            mac_address: mac,
            on: data[mac].on,
            devices,
            active_alarm,
            status,
            chk_watch: chk_sum.count,
            acknow: chk_sum.acknow,
            acknow_count: chk_sum.acknow_count,
            offline_count,
            offline_timestamp,
        }
    }
}
// Build Final Payload
const arr_data = [];
const chk_offline = global.get("Offline") || {};
const communications = global.get("CheckCommunications") || {};

for (let conf of msg.config_url) {
    const mac = conf.mac_address;
    const compares = comparesData(mac)[mac];

    if (!chk_offline[mac]) {
        arr_data.push({
            store_name: data[mac]?.name ?? conf.xweb_name,
            mac,
            url: conf.external_ip,
            communication: "Online",
            owner: conf.owner,
            note: "",
            alarm: compares.status,
            chk_watch: compares.chk_watch,
            acknow: compares.acknow,
            acknow_count: compares.acknow_count,
            offline_count: compares.offline_count,
            offline_timestamp: compares.offline_timestamp || date_now,
        });
    } else {
        arr_data.push({
            store_name: conf.xweb_name,
            mac,
            url: conf.external_ip,
            communication: "Offline",
            owner: conf.owner,
            note: chk_offline[mac]?.acknow ? chk_offline[mac]?.text || "Acknowledge" : "",
            date_offline: chk_offline[mac]?.dateStart || date_now,
            acknow_offline: chk_offline[mac]?.acknow || false,
            alarm: { active: 0, total: 0 },
            chk_watch: 0,
            acknow: 0,
            acknow_count: 0,
            offline_count: communications[mac]?.offline_count || 0,
            offline_timestamp: communications[mac]?.offline_timestamp || date_now,
        })
    }
}
msg.payload = arr_data;
msg.filename = "/data/files/Aggregate_Alarms.txt";
return msg;
